#define I2C_BUS             0
#define OV2640_I2C_ADDR     0x30  
// 直接把物理地址映射为 32位 变量，
#define GPIO0_EXT_PORT  (*(volatile unsigned int *)(0x41010070))

// 定义同步引脚在 32位 寄存器中的对应位号
#define BIT_VSYNC (1 << 8)  // PB0 是第 8 位
#define BIT_HREF  (1 << 9)  // PB1 是第 9 位
#define BIT_PCLK  (1 << 14) // PB6 是第 14 位
static I2cBusIo m_i2cBus = {
    .scl = { .gpio = GPIO0_PA1, .func = MUX_FUNC3, .type = PULL_UP, .drv = DRIVE_KEEP, .dir = LZGPIO_DIR_KEEP, .val = LZGPIO_LEVEL_KEEP },
    .sda = { .gpio = GPIO0_PA0, .func = MUX_FUNC3, .type = PULL_UP, .drv = DRIVE_KEEP, .dir = LZGPIO_DIR_KEEP, .val = LZGPIO_LEVEL_KEEP },
    .id = FUNC_ID_I2C0, .mode = FUNC_MODE_M2,
};

static int ov2640_write_reg(unsigned char reg, unsigned char data) {
    unsigned char send_data[2] = {reg, data};
    if (LzI2cWrite(I2C_BUS, OV2640_I2C_ADDR, send_data, 2) != LOS_OK) return -1;
    return 0;
}

static int ov2640_write_array(const unsigned char (*array)[2]) {
    int i = 0;
    while (array[i][0] != 0xff || array[i][1] != 0xff) {
        ov2640_write_reg(array[i][0], array[i][1]);
        i++;
        LOS_Msleep(1); 
    }
    return 0;
}

