static void rk2206_gpio_input_init(void) 
{
    int i; 
    unsigned int pins[11] = {
        GPIO0_PB0, GPIO0_PB1, GPIO0_PB6,
        GPIO0_PB4, GPIO0_PB5, GPIO0_PB2, GPIO0_PB7,
        GPIO0_PC0, GPIO0_PC1, GPIO0_PC2, GPIO0_PC3
    };
    for (i = 0; i < 11; i++) {
        LzGpioInit(pins[i]);
        PinctrlSet(pins[i], MUX_FUNC0, PULL_DOWN, DRIVE_LEVEL0); 
        LzGpioSetDir(pins[i], LZGPIO_DIR_IN);
    }
}

int OV2640_Init(void) 
{
    printf("\n====== 开始初始化 OV2640 ======\n");
    I2cIoInit(m_i2cBus);
    LzI2cInit(I2C_BUS, 100000);
    PinctrlSet(GPIO0_PA1, MUX_FUNC3, PULL_UP, DRIVE_KEEP);
    PinctrlSet(GPIO0_PA0, MUX_FUNC3, PULL_UP, DRIVE_KEEP);
    LOS_Msleep(500); 

    rk2206_gpio_input_init();
    LOS_Msleep(100);

    if (ov2640_write_array(ov2640_full_init_reg) != 0) {
        printf("❌ OV2640 寄存器配置失败！\n");
        return -1;
    }
    printf("🎉 OV2640 初始化完成！准备拍摄！\n");
    return 0;
}

int OV2640_Capture_JPEG(unsigned char *buf, int max_len) 
{
    int len = 0;
    unsigned int val;       // 用来一瞬间接住 32 根引脚的状态
    unsigned char byte_val; // 用来存放拼装好的像素字节
    int timeout = 0;

    printf("\n>>> 正在跳过前 3 帧未曝光稳定的垃圾画面... <<<\n");
    for (int f = 0; f < 3; f++) {
        timeout = 0;
        do { val = GPIO0_EXT_PORT; timeout++; if(timeout > 2000000) goto timeout_exit; } while ((val & BIT_VSYNC) == 0);
        timeout = 0;
        do { val = GPIO0_EXT_PORT; timeout++; if(timeout > 2000000) goto timeout_exit; } while ((val & BIT_VSYNC) != 0);
    }

    printf(">>> 摄像头曝光稳定，启动极速直读引擎！请保持静止... <<<\n");

    // 捕获第 4 帧
    timeout = 0;
    do { val = GPIO0_EXT_PORT; timeout++; if(timeout > 2000000) goto timeout_exit; } while ((val & BIT_VSYNC) == 0);
    timeout = 0;
    do { val = GPIO0_EXT_PORT; timeout++; if(timeout > 2000000) goto timeout_exit; } while ((val & BIT_VSYNC) != 0);

    while (1) {
        val = GPIO0_EXT_PORT;
        if (val & BIT_VSYNC) break; // 遇到 VSYNC 拉高，这帧结束

        if (val & BIT_HREF) { 
            // 极速死等 PCLK 拉高
            timeout = 0;
            do { val = GPIO0_EXT_PORT; timeout++; if(timeout > 50000) goto end_frame; } while ((val & BIT_PCLK) == 0);
            
            // 【核心魔法】仅需位运算，瞬间重组 D0-D7 引脚
            // 屏蔽掉 PB6(PCLK,对应位2)的干扰，并把 PB2(D2) 补进第二位
            byte_val = ((val >> 12) & 0xFB) | ((val >> 8) & 0x04);
            
            // 存入内存 (保留前两个字节的空间，供主程序缝合 FF D8)
            if (len + 2 < max_len) {
                buf[len + 2] = byte_val;
                len++;
            }

            // 极速死等 PCLK 拉低
            timeout = 0;
            do { val = GPIO0_EXT_PORT; timeout++; if(timeout > 50000) goto end_frame; } while ((val & BIT_PCLK) != 0);
        }
    }
    
end_frame:
    printf(">>> 物理捕获结束，总计读取到 %d 字节数据！ <<<\n", len);
    return len;

timeout_exit:
    printf(">>> ❌ 等待信号超时！已强制退出，防止系统卡死！ <<<\n");
    return 0;
}